def server(port):
    sock = socket.socket()
    ai = socket.getaddrinfo("0.0.0.0", port)
    addr = ai[0][-1]
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    sock.bind(addr)
    sock.listen(5)
    
    print("Server Started")

